class Solution:
    def scheduleCourse(self, courses: List[List[int]]) -> int:
        courses.sort(key=lambda x: x[1])
        heap=[]; t=0
        for d,dl in courses:
            heapq.heappush(heap,-d); t+=d
            if t>dl: t+=heapq.heappop(heap)
        return len(heap)

