class Solution {
public:
    int scheduleCourse(vector<vector<int>>& c) {
        sort(c.begin(),c.end(),[](auto&a,auto&b){return a[1]<b[1];});
        priority_queue<int> pq; long t=0;
        for(auto& v:c){
            t+=v[0]; pq.push(v[0]);
            if(t>v[1]){ t-=pq.top(); pq.pop(); }
        }
        return pq.size();
    }
};

